import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import ProductsList from './ProductsList';
import Auth from './Auth';
import Admin from './Admin';
import Profile from './Profile';
import { supabase } from './supabaseClient';


function ProtectedRoute({ session, role, requireAdmin, children }) {
  if (!session || !session.user) {
    return <Navigate to="/login" replace />;
  }
  if (requireAdmin && role !== 'admin') {
    return <Navigate to="/" replace />;
  }
  return children;
}



function App() {
  const [session, setSession] = useState(null);
  const [role, setRole] = useState(null);
  const location = useLocation();

  useEffect(() => {
    setSession(supabase.auth.getSessionSync?.() || supabase.auth.session || null);
    const { data: listener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => {
      listener?.subscription?.unsubscribe?.();
    };
  }, []);

  useEffect(() => {
    const fetchRole = async () => {
      if (session && session.user) {
        const { data, error } = await supabase
          .from('profiles')
          .select('role')
          .eq('user_id', session.user.id)
          .single();
        setRole(data?.role || null);
        // Redirect admin to /admin after login
        if (data?.role === 'admin' && window.location.pathname === '/login') {
          window.location.replace('/admin');
        }
      } else {
        setRole(null);
      }
    };
    fetchRole();
  }, [session, location.pathname]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setSession(null);
    setRole(null);
  };

  return (
    <Router>
      <div className="App">
        <h1>My Product Store</h1>
        <nav>
          <Link to="/">Home</Link> |{' '}
          <Link to="/admin">Admin</Link> |{' '}
          <Link to="/profile">Profile</Link>
          {session && session.user && (
            <button onClick={handleLogout} style={{ marginLeft: 10 }}>Logout</button>
          )}
        </nav>
        <Routes>
          <Route path="/" element={<ProductsList />} />
          <Route path="/login" element={<Auth onAuth={() => setSession(supabase.auth.getSessionSync?.() || supabase.auth.session || null)} />} />
          <Route path="/admin" element={
            <ProtectedRoute session={session} role={role} requireAdmin={true}>
              <Admin />
            </ProtectedRoute>
          } />
          <Route path="/profile" element={
            <ProtectedRoute session={session} role={role}>
              <Profile session={session} role={role} />
            </ProtectedRoute>
          } />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
